package ConzyNestapp.com.CozyNest.Controller;import ConzyNestapp.com.CozyNest.Dto.RoomDto;import ConzyNestapp.com.CozyNest.Service.RoomService;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.stereotype.Component;import org.springframework.web.bind.annotation.*;import java.util.List;import java.util.Map;@RestController@RequiredArgsConstructor@Component@RequestMapping("/admin/hotels/{hotelid}/rooms")@Slf4jpublic class AdminRoomController {    private final RoomService roomService;    @GetMapping    public ResponseEntity<List< RoomDto>> getAllRoomsByHotel(@PathVariable(name="hotelid") Long hotelid){       List<RoomDto> roomList=roomService.getAllRoomHotel(hotelid);       return new ResponseEntity<>(roomList, HttpStatus.FOUND);    }    @GetMapping("/{roomid}")    public ResponseEntity<RoomDto> getRoom(@PathVariable(name="roomid") long roomid){        return new ResponseEntity<>(roomService.getRoomById(roomid),HttpStatus.FOUND);    }    @PostMapping    public ResponseEntity<RoomDto> createRoom(@RequestBody RoomDto roomDto,@PathVariable(name="hotelid") Long hotelid){        return new ResponseEntity<>(roomService.createRoomForHotel(hotelid,roomDto),HttpStatus.CREATED);    }    @PatchMapping("/{Roomid}")    public ResponseEntity<RoomDto> updateRoom(@RequestBody Map<String,String> changes, @PathVariable(name="Roomid") Long roomid){        return new ResponseEntity<>(roomService.updateRoomDetails(roomid,changes),HttpStatus.OK);    }    @DeleteMapping("/{Roomid}")    public ResponseEntity<RoomDto> DeleteRoom( @PathVariable(name="Roomid") Long roomId){        roomService.deleteRoomById(roomId);        return ResponseEntity.noContent().build();    }}